#!/bin/bash
set -e # Exit immediately if a command exits with a non-zero status.

# --- Configuration Area ---
# Ensure this base name matches the one used during compression
LOG_BASE_NAME="bytedance"
# Directory containing the output of your custom algorithm's compression
YOUR_ALGO_COMPRESSED_DIR="output/${LOG_BASE_NAME}"

# Base name for directories generated by the Python compression script
PYTHON_COMPRESSED_DIR_BASE="${LOG_BASE_NAME}.log_compressed_chunks"

# Number of threads to use for testing
THREADS=4
# Directory to save performance statistics
OUTPUT_DIR="benchmark_results_cpu_decompress"


# --- Script Core ---

# Check if required commands exist
for cmd in python3 /usr/bin/time ./decompress; do
    if ! command -v "$cmd" &> /dev/null; then
        echo "Error: Command not found: $cmd"
        echo "Please ensure python3, /usr/bin/time, and your ./decompress program are in your PATH or the current directory."
        exit 1
    fi
done

# Check if the Python decompression script exists
if [ ! -f "general_decompressor.py" ]; then
    echo "Error: Python decompression script 'general_decompressor.py' not found."
    exit 1
fi

# Check if compressed data directories exist
GZIP_DIR="${PYTHON_COMPRESSED_DIR_BASE}_gzip"
BROTLI_DIR="${PYTHON_COMPRESSED_DIR_BASE}_brotli"
LZ4_DIR="${PYTHON_COMPRESSED_DIR_BASE}_lz4"

if ! { [ -d "$YOUR_ALGO_COMPRESSED_DIR" ] && [ -d "$GZIP_DIR" ] && [ -d "$BROTLI_DIR" ] && [ -d "$LZ4_DIR" ]; }; then
    echo "Error: One or more compressed data directories not found."
    echo "Please run the compression benchmark first to generate the following directories:"
    echo " - ${YOUR_ALGO_COMPRESSED_DIR}"
    echo " - ${GZIP_DIR}"
    echo " - ${BROTLI_DIR}"
    echo " - ${LZ4_DIR}"
    exit 1
fi


mkdir -p "$OUTPUT_DIR"
echo "CPU/Memory decompression performance test results will be saved in the '${OUTPUT_DIR}' directory."
echo "All decompression output will be redirected to /dev/null to focus on computational performance."
echo ""

# run_test function
# Argument 1: Test name
# Argument 2...: The full command to execute
run_test() {
    local test_name=$1
    shift
    local cmd_to_run=("$@")

    echo "--- [START] Test: ${test_name} ---"
    
    # Run the command with /usr/bin/time -v and output stats to a file
    # The command's own standard output is redirected to /dev/null
    /usr/bin/time -v -o "${OUTPUT_DIR}/${test_name}_stats.txt" "${cmd_to_run[@]}" > /dev/null
    
    echo "Statistics saved to: ${OUTPUT_DIR}/${test_name}_stats.txt"
    echo "--- [END] Test: ${test_name} ---"
    echo ""
}

# --- Execute All Decompression Tests ---

# 1. Test your custom decompression algorithm
# Syntax: ./decompress <input_directory> <output_file> <threads>
# We set the output file to /dev/null
run_test "MyAlgorithm_Decompress" \
    ./decompress "$YOUR_ALGO_COMPRESSED_DIR" /dev/null "$THREADS"

# 2. Test Brotli decompression
run_test "Brotli_Decompress" \
    python3 general_decompressor.py "$BROTLI_DIR" ./bytedance.log -a brotli -t "$THREADS"

# 3. Test Gzip decompression
run_test "Gzip_Decompress" \
    python3 general_decompressor.py "$GZIP_DIR" /dev/null -a gzip -t "$THREADS"

# 4. Test LZ4 decompression
run_test "LZ4_Decompress" \
    python3 general_decompressor.py "$LZ4_DIR" /dev/null -a lz4 -t "$THREADS"

echo "All CPU/Memory decompression benchmarks are complete!"